class MyPromiseV2 {
  constructor(executor) {
    this.state = 'pending';
    this.result = undefined;
    this.fulfilledQueue = [];
    this.rejectedQueue = [];

    const resolve = (value) => {
      if (this.state !== 'pending') return;
      this.state = 'fulfilled';
      this.result = value;
      this.fulfilledQueue.forEach(cb => cb()); // 注意这里不再传 result
    };

    const reject = (reason) => {
      if (this.state !== 'pending') return;
      this.state = 'rejected';
      this.result = reason;
      this.rejectedQueue.forEach(cb => cb());
    };

    try {
      executor(resolve, reject);
    } catch (error) {
      reject(error);
    }
  }

  then(onFulfilled, onRejected) {
    // 关键升级：返回一个全新的 Promise
    const newPromise = new MyPromiseV2((resolve, reject) => {
      const scheduleFulfilled = () => {
        // 使用 setTimeout 模拟异步微任务
        setTimeout(() => {
          try {
            if (!onFulfilled) {
              // 如果没有提供 onFulfilled，则直接 resolve 上一个 promise 的结果
              resolve(this.result);
            } else {
              // 执行回调，并拿到返回值
              const x = onFulfilled(this.result);
              // resolvePromise 会处理返回值 x
              resolvePromise(newPromise, x, resolve, reject);
            }
          } catch (error) {
            reject(error);
          }
        }, 0);
      };

      const scheduleRejected = () => {
        setTimeout(() => {
          try {
            if (!onRejected) {
              reject(this.result);
            } else {
              const x = onRejected(this.result);
              resolvePromise(newPromise, x, resolve, reject);
            }
          } catch (error) {
            reject(error);
          }
        }, 0);
      };

      if (this.state === 'fulfilled') {
        scheduleFulfilled();
      } else if (this.state === 'rejected') {
        scheduleRejected();
      } else if (this.state === 'pending') {
        this.fulfilledQueue.push(scheduleFulfilled);
        this.rejectedQueue.push(scheduleRejected);
      }
    });

    return newPromise;
  }
}

/**
 * 这是一个核心辅助函数，用来处理 .then 回调函数的返回值 x
 * @param {MyPromiseV2} newPromise then 方法返回的新 Promise
 * @param {*} x onFulfilled 或 onRejected 的返回值
 * @param {Function} resolve newPromise 的 resolve 函数
 * @param {Function} reject newPromise 的 reject 函数
 */
function resolvePromise(newPromise, x, resolve, reject) {
  // 防止循环引用
  if (newPromise === x) {
    return reject(new TypeError('Chaining cycle detected for promise'));
  }

  // 如果 x 是一个 Promise，则 newPromise 的状态跟随 x 的状态
  if (x instanceof MyPromiseV2) {
    x.then(resolve, reject);
  } 
  // 如果 x 是一个普通值，则直接 resolve
  else {
    resolve(x);
  }
}
